queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?amusement_parks a :AmusementPark .
    ?amusement_parks p:name ?name .
    ?amusement_parks p:location ?location_f .
    FILTER(STR(?location_f) = "Orlando, Florida")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?water_parks a :WaterPark .
    ?water_parks p:name ?name .
    ?water_parks p:location ?location_f .
    FILTER(STR(?location_f) = "Orlando, Florida")
    BIND(?name AS ?o0)
  }
}

